const items = $input.all();
const now = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);

function getSource(link) {
  if (!link) return 'Desconhecido';
  if (link.includes('thehackernews')) return 'The Hacker News';
  if (link.includes('bleepingcomputer')) return 'Bleeping Computer';
  if (link.includes('krebsonsecurity')) return 'KrebsOnSecurity';
  return 'Outro';
}

const recent = items.filter(item => {
  const dateStr = item.json.pubDate || item.json.isoDate || item.json.date;
  if (!dateStr) return true;
  return new Date(dateStr) >= yesterday;
});

if (recent.length === 0) {
  return [{ json: { noNews: true, totalArticles: 0 } }];
}

const lista = recent.map((item, i) => {
  const source = getSource(item.json.link);
  const title = item.json.title || 'Sem titulo';
  const link = item.json.link || '';
  const snippet = (item.json.contentSnippet || item.json.summary || '').substring(0, 400);
  return `${i + 1}. [${source}] ${title}\nLink: ${link}\n${snippet}`;
}).join('\n\n---\n\n');

const prompt = `Voce e um analista senior de cyberseguranca. Analise as ${recent.length} noticias abaixo das ultimas 24h e gere um digest em HTML.

Para cada noticia use este formato:
<div style="border-left:4px solid #e74c3c;padding:10px;margin:10px 0;background:#fff">
  <span style="font-size:11px;font-weight:bold;color:COR">CRITICIDADE: NIVEL</span>
  <h3 style="margin:4px 0">[TITULO DA NOTICIA]</h3>
  <p style="color:#444">RESUMO EM 2-3 FRASES EM PORTUGUES SOBRE O IMPACTO.</p>
  <a href="LINK" style="color:#3498db">Leia a noticia completa</a>
</div>

Cores por criticidade: ALTA=#e74c3c, MEDIA=#f39c12, BAIXA=#27ae60

Criterios:
- ALTA: vuln critica (CVSS 9+), ataque ativo em larga escala, breach massivo de dados
- MEDIA: patch importante, nova tecnica de ataque, campanha de phishing significativa
- BAIXA: pesquisa academica, tendencia de mercado, noticia informativa

Ao final adicione:
<div style="background:#2c3e50;color:#fff;padding:15px;border-radius:6px;margin-top:20px">
  <h2 style="margin:0 0 10px">Briefing Executivo do Dia</h2>
  <p style="margin:0;line-height:1.6">PARAGRAFO DE 4-5 LINHAS RESUMINDO OS TEMAS MAIS CRITICOS E TENDENCIAS DO DIA.</p>
</div>

NOTICIAS:
${lista}`;

return [{ json: { prompt, totalArticles: recent.length, noNews: false } }];
